-- 운동복 컨셉 이미지로 교체 (Unsplash, 검증 완료)

delete from public.product_images;


update public.reviews rv
set review_image_url = m.url
from (select id, (row_number() over (order by created_at) - 1) as rn from public.reviews) r
join (values (0, 'https://images.unsplash.com/photo-1549476464-37392f717541?auto=format&fit=crop&w=240&h=320&q=72'), (1, 'https://images.unsplash.com/photo-1583454110551-21f2fa2afe61?auto=format&fit=crop&w=240&h=320&q=72'), (2, 'https://images.unsplash.com/photo-1483721310020-03333e577078?auto=format&fit=crop&w=240&h=320&q=72'), (3, 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?auto=format&fit=crop&w=240&h=320&q=72'), (4, 'https://images.unsplash.com/photo-1534368420009-621bfab424a8?auto=format&fit=crop&w=240&h=320&q=72'), (5, 'https://images.unsplash.com/photo-1596357395217-80de13130e92?auto=format&fit=crop&w=240&h=320&q=72'), (6, 'https://images.unsplash.com/photo-1461897104016-0b3b00cc81ee?auto=format&fit=crop&w=240&h=320&q=72'), (7, 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?auto=format&fit=crop&w=240&h=320&q=72')) as m(idx, url)
  on (r.rn % 8) = m.idx
where rv.id = r.id;
